102	        cublas_wrapper.setBF16GemmConfig();
103	    }
104	#endif
105	    else if (std::is_same<T, float>::value) {
106	        cublas_wrapper.setFP32GemmConfig();
107	    }
108	
109	    BertWeight<T> bert_weights(hidden_units, inter_size, num_layers);
110	
111	    AttentionType attention_type = getAttentionType<T>(size_per_head, getSMVersion(), is_remove_padding, seq_len);
112	
113	    Bert<T> bert = Bert<T>(0,  // max_batch_size_, deprecated
114	                           0,  // max_seq_len_, deprecated
115	                           head_num,
116	                           size_per_head,
117	                           inter_size,
118	                           num_layers,
119	                           getSMVersion(),
120	                           1.0f,
